import { TechSnippetData } from "./technologySnippets";

const s = (c: string) => c.split("\n");

const createEnterpriseTech = (name: string, lang: string, snippetData: { t: string; c: string }[]): TechSnippetData => ({
  snippets: [
    { title: snippetData[0].t, language: lang, badge: "🔒 Secure Code", badgeColor: "#60A5FA", description: `Enterprise security configuration for ${name}. At WebQ, we enforce strict access controls and encryption for all ${name} deployments.`, lines: s(snippetData[0].c) },
    { title: snippetData[1].t, language: lang, badge: "⚡ Performance", badgeColor: "#7DB8F5", description: `Performance optimization for ${name}. At WebQ, we tune ${name} for maximum throughput and responsiveness.`, lines: s(snippetData[1].c) },
    { title: snippetData[2].t, language: lang, badge: "🧪 Testing", badgeColor: "#93C5FD", description: `Integration testing for ${name}. At WebQ, we validate all ${name} configurations in staging before production.`, lines: s(snippetData[2].c) },
    { title: snippetData[3].t, language: lang, badge: "📝 Logging", badgeColor: "#A5D0FB", description: `Audit logging for ${name}. At WebQ, we capture comprehensive audit trails for compliance and troubleshooting.`, lines: s(snippetData[3].c) },
    { title: snippetData[4].t, language: lang, badge: "🛡️ Exception Handling", badgeColor: "#6CB4EE", description: `Error handling and recovery for ${name}. At WebQ, we implement graceful degradation and automated recovery.`, lines: s(snippetData[4].c) },
    { title: snippetData[5].t, language: lang, badge: "👤 User-Friendly", badgeColor: "#87CEEB", description: `User experience optimization for ${name}. At WebQ, we design intuitive interfaces and streamlined workflows.`, lines: s(snippetData[5].c) },
    { title: snippetData[6].t, language: lang, badge: "📐 Best Practice", badgeColor: "#79B8F8", description: `${name} best practices and architecture. At WebQ, we follow industry standards for scalable, maintainable solutions.`, lines: s(snippetData[6].c) },
    { title: snippetData[7].t, language: lang, badge: "🔄 Event-Driven", badgeColor: "#5DADE2", description: `Integration and automation for ${name}. At WebQ, we build event-driven workflows and system integrations.`, lines: s(snippetData[7].c) },
    { title: snippetData[8].t, language: "Markdown", badge: "📖 Documentation", badgeColor: "#A0C4E8", description: `${name} implementation documentation. At WebQ, we maintain comprehensive runbooks for every deployment.`, lines: s(snippetData[8].c) },
  ],
  metrics: [],
  industries: [],
  webqCallout: `At WebQ, we deliver enterprise-grade ${name} solutions with security, performance, and reliability built in from day one.`,
});

export const sap: TechSnippetData = createEnterpriseTech("SAP", "ABAP", [
  { t: "authorization_check.abap", c: "* SAP Authorization Check\nAUTHORITY-CHECK OBJECT 'S_TCODE'\n  ID 'TCD' FIELD 'VA01'.\nIF sy-subrc <> 0.\n  MESSAGE e001(zmsg)\n    WITH 'No authorization for VA01'.\nENDIF.\n\n* Field-level authorization\nAUTHORITY-CHECK OBJECT 'V_VBAK_AAT'\n  ID 'AUART' FIELD 'ZOR'\n  ID 'ACTVT' FIELD '03'.\n\n* Audit trail\nCALL FUNCTION 'SWNC_COLLECTOR_GET_AGGREGATES'\n  EXPORTING i_component = 'TOTAL'\n  TABLES    aggusertcode = lt_audit." },
  { t: "performance_tuning.abap", c: "* SAP Performance Optimization\n* Use FOR ALL ENTRIES instead of nested SELECTs\nSELECT vbeln erdat kunnr\n  FROM vbak\n  INTO TABLE @DATA(lt_orders)\n  WHERE erdat >= @lv_date.\n\nIF lt_orders IS NOT INITIAL.\n  SELECT vbeln posnr matnr kwmeng\n    FROM vbap\n    FOR ALL ENTRIES IN @lt_orders\n    WHERE vbeln = @lt_orders-vbeln\n    INTO TABLE @DATA(lt_items).\nENDIF.\n\n* Buffer tables for frequent reads\nCALL FUNCTION 'DEQUEUE_ALL'\n  EXPORTING mode_vbak = 'S'." },
  { t: "unit_test.abap", c: "* ABAP Unit Test\nCLASS ltcl_order_test DEFINITION\n  FOR TESTING RISK LEVEL HARMLESS.\n  PRIVATE SECTION.\n    DATA: mo_cut TYPE REF TO zcl_order_processor.\n    METHODS:\n      setup,\n      test_valid_order FOR TESTING,\n      test_invalid_qty FOR TESTING.\nENDCLASS.\n\nCLASS ltcl_order_test IMPLEMENTATION.\n  METHOD setup.\n    mo_cut = NEW zcl_order_processor( ).\n  ENDMETHOD.\n  METHOD test_valid_order.\n    DATA(lv_result) = mo_cut->validate( iv_qty = 10 ).\n    cl_abap_unit_assert=>assert_true( lv_result ).\n  ENDMETHOD.\nENDCLASS." },
  { t: "audit_log.abap", c: "* SAP Change Document Logging\nCALL FUNCTION 'CHANGEDOCUMENT_OPEN'\n  EXPORTING objectclass = 'ZORDER'\n            objectid    = lv_order_id.\n\nCALL FUNCTION 'CHANGEDOCUMENT_SINGLE_CASE'\n  EXPORTING tablename  = 'ZVBAK'\n            workarea_old = ls_old\n            workarea_new = ls_new.\n\nCALL FUNCTION 'CHANGEDOCUMENT_CLOSE'\n  EXPORTING objectclass = 'ZORDER'\n            objectid    = lv_order_id\n            tcode       = sy-tcode\n            udate       = sy-datum\n            utime       = sy-uzeit\n            username    = sy-uname." },
  { t: "error_handling.abap", c: "* SAP Exception Handling\nTRY.\n    DATA(lo_order) = zcl_order_factory=>create(\n      iv_type = 'ZOR'\n      iv_customer = lv_kunnr\n    ).\n    lo_order->validate( ).\n    lo_order->save( ).\n    COMMIT WORK AND WAIT.\n  CATCH zcx_validation_error INTO DATA(lx_val).\n    MESSAGE lx_val->get_text( ) TYPE 'E'.\n    ROLLBACK WORK.\n  CATCH zcx_save_error INTO DATA(lx_save).\n    MESSAGE lx_save->get_text( ) TYPE 'E'.\n    ROLLBACK WORK.\n  CATCH cx_root INTO DATA(lx_root).\n    MESSAGE lx_root->get_text( ) TYPE 'E'.\n    ROLLBACK WORK.\nENDTRY." },
  { t: "fiori_app.js", c: "// SAP Fiori UI5 Application\nsap.ui.define([\n  'sap/ui/core/mvc/Controller',\n  'sap/m/MessageToast'\n], function(Controller, MessageToast) {\n  return Controller.extend('webq.orders.Main', {\n    onInit: function() {\n      var oModel = new sap.ui.model.odata.v4.ODataModel({\n        serviceUrl: '/sap/opu/odata4/webq/orders/'\n      });\n      this.getView().setModel(oModel);\n    },\n    onCreateOrder: function() {\n      var oContext = this.getView().getModel()\n        .bindList('/Orders').create({});\n      MessageToast.show('Order created');\n    }\n  });\n});" },
  { t: "btp_config.json", c: "{\n  \"_schema-version\": \"3.1\",\n  \"ID\": \"webq-order-app\",\n  \"modules\": [\n    {\n      \"name\": \"order-srv\",\n      \"type\": \"nodejs\",\n      \"path\": \"srv\",\n      \"requires\": [\n        {\"name\": \"order-db\"},\n        {\"name\": \"order-auth\"}\n      ]\n    },\n    {\n      \"name\": \"order-db-deployer\",\n      \"type\": \"hdb\",\n      \"path\": \"db\"\n    }\n  ],\n  \"resources\": [\n    {\"name\": \"order-auth\", \"type\": \"org.cloudfoundry.managed-service\",\n     \"parameters\": {\"service\": \"xsuaa\", \"service-plan\": \"application\"}}\n  ]\n}" },
  { t: "cpi_integration.groovy", c: "// SAP CPI Integration Flow\nimport com.sap.gateway.ip.core.customdev.util.Message\n\ndef Message processData(Message message) {\n    def body = message.getBody(String)\n    def xml = new XmlSlurper().parseText(body)\n\n    // Transform SAP IDoc to REST API format\n    def orders = xml.ORDERS05.collect { order ->\n        [\n            orderId: order.BELNR.text(),\n            customer: order.KUNNR.text(),\n            items: order.E1EDP01.collect { item ->\n                [material: item.MATNR.text(),\n                 quantity: item.MENGE.text()]\n            }\n        ]\n    }\n\n    message.setBody(groovy.json.JsonOutput.toJson(orders))\n    return message\n}" },
  { t: "README.md", c: "# SAP Implementation Guide\n\n## Modules\n| Module | Purpose |\n|--------|---------|\n| S/4HANA | Core ERP |\n| Fiori | User Interface |\n| BTP | Cloud Platform |\n| CPI | Integration |\n\n## Custom Development\n- ABAP Clean Code standards\n- Unit tests required (>80%)\n- Transport management via ChaRM\n\n## Integration\n- APIs: OData v4\n- Events: SAP Event Mesh\n- Files: SFTP / Cloud Storage\n\n## Support\n- L1: ServiceNow tickets\n- L2: SAP Basis team\n- L3: SAP support portal" },
]);
