export const salesforce: TechSnippetData = createEnterpriseTech("Salesforce", "Apex", [
  { t: "security_controller.cls", c: "// Salesforce Apex with Security\npublic with sharing class OrderController {\n    @AuraEnabled(cacheable=true)\n    public static List<Order__c> getOrders() {\n        // CRUD/FLS check\n        if (!Schema.sObjectType.Order__c.isAccessible()) {\n            throw new AuraHandledException('Insufficient access');\n        }\n        return [\n            SELECT Id, Name, Total__c, Status__c\n            FROM Order__c\n            WHERE OwnerId = :UserInfo.getUserId()\n            WITH SECURITY_ENFORCED\n            ORDER BY CreatedDate DESC\n            LIMIT 100\n        ];\n    }\n}" },
  { t: "batch_processor.cls", c: "// Salesforce Batch Apex\npublic class OrderBatchProcessor\n    implements Database.Batchable<sObject>, Database.Stateful {\n\n    private Integer successCount = 0;\n    private Integer errorCount = 0;\n\n    public Database.QueryLocator start(Database.BatchableContext bc) {\n        return Database.getQueryLocator([\n            SELECT Id, Status__c FROM Order__c\n            WHERE Status__c = 'Processing'\n        ]);\n    }\n\n    public void execute(Database.BatchableContext bc,\n                        List<Order__c> scope) {\n        for (Order__c order : scope) {\n            order.Status__c = 'Completed';\n        }\n        Database.SaveResult[] results =\n            Database.update(scope, false);\n        for (Database.SaveResult sr : results) {\n            if (sr.isSuccess()) successCount++;\n            else errorCount++;\n        }\n    }\n}" },
  { t: "order_test.cls", c: "// Salesforce Apex Test\n@isTest\nprivate class OrderControllerTest {\n    @TestSetup\n    static void setupData() {\n        Account acc = new Account(Name='Test Corp');\n        insert acc;\n        List<Order__c> orders = new List<Order__c>();\n        for (Integer i = 0; i < 10; i++) {\n            orders.add(new Order__c(\n                Account__c = acc.Id,\n                Total__c = 100 * (i + 1),\n                Status__c = 'New'\n            ));\n        }\n        insert orders;\n    }\n\n    @isTest\n    static void testGetOrders() {\n        List<Order__c> result = OrderController.getOrders();\n        System.assertNotEquals(0, result.size(),\n            'Should return orders');\n    }\n}" },
  { t: "event_logging.cls", c: "// Salesforce Platform Event Logging\npublic class AuditLogger {\n    public static void log(String action,\n                           String objectType,\n                           String recordId) {\n        Audit_Event__e event = new Audit_Event__e(\n            Action__c = action,\n            Object_Type__c = objectType,\n            Record_Id__c = recordId,\n            User_Id__c = UserInfo.getUserId(),\n            Timestamp__c = DateTime.now()\n        );\n        Database.SaveResult sr =\n            EventBus.publish(event);\n        if (!sr.isSuccess()) {\n            System.debug(LoggingLevel.ERROR,\n                'Audit event publish failed: '\n                + sr.getErrors());\n        }\n    }\n}" },
  { t: "error_handler.cls", c: "// Salesforce Error Handling\npublic class OrderService {\n    public class OrderException extends Exception {}\n\n    public static Order__c processOrder(Id orderId) {\n        Savepoint sp = Database.setSavepoint();\n        try {\n            Order__c order = [SELECT Id, Status__c\n                FROM Order__c WHERE Id = :orderId\n                FOR UPDATE];\n            if (order.Status__c == 'Cancelled') {\n                throw new OrderException(\n                    'Cannot process cancelled order');\n            }\n            order.Status__c = 'Processing';\n            update order;\n            return order;\n        } catch (QueryException e) {\n            Database.rollback(sp);\n            throw new AuraHandledException('Order not found');\n        } catch (DmlException e) {\n            Database.rollback(sp);\n            throw new AuraHandledException(e.getMessage());\n        }\n    }\n}" },
  { t: "lightning_component.js", c: "// Salesforce Lightning Web Component\nimport { LightningElement, wire } from 'lwc';\nimport getOrders from '@salesforce/apex/OrderController.getOrders';\nimport { ShowToastEvent } from 'lightning/platformShowToastEvent';\n\nexport default class OrderList extends LightningElement {\n    orders;\n    error;\n\n    @wire(getOrders)\n    wiredOrders({ data, error }) {\n        if (data) {\n            this.orders = data;\n            this.error = undefined;\n        } else if (error) {\n            this.error = error.body.message;\n            this.dispatchEvent(new ShowToastEvent({\n                title: 'Error',\n                message: this.error,\n                variant: 'error'\n            }));\n        }\n    }\n}" },
  { t: "flow_config.json", c: "// Salesforce Flow Configuration\n{\n  \"name\": \"Order_Approval_Flow\",\n  \"type\": \"AutoLaunchedFlow\",\n  \"triggerType\": \"RecordAfterSave\",\n  \"object\": \"Order__c\",\n  \"conditions\": [\n    {\"field\": \"Total__c\", \"operator\": \"GreaterThan\", \"value\": 10000},\n    {\"field\": \"Status__c\", \"operator\": \"Equals\", \"value\": \"New\"}\n  ],\n  \"actions\": [\n    {\n      \"type\": \"CreateRecord\",\n      \"object\": \"Approval__c\",\n      \"fields\": {\n        \"Order__c\": \"{!$Record.Id}\",\n        \"Approver__c\": \"{!$Record.Owner.ManagerId}\"\n      }\n    },\n    {\n      \"type\": \"SendEmail\",\n      \"template\": \"Order_Approval_Request\"\n    }\n  ]\n}" },
  { t: "api_integration.cls", c: "// Salesforce REST API Integration\npublic class ExternalOrderSync {\n    @future(callout=true)\n    public static void syncOrder(Id orderId) {\n        Order__c order = [SELECT Id, Name, Total__c\n            FROM Order__c WHERE Id = :orderId];\n\n        HttpRequest req = new HttpRequest();\n        req.setEndpoint('callout:ERP_System/api/orders');\n        req.setMethod('POST');\n        req.setHeader('Content-Type', 'application/json');\n        req.setBody(JSON.serialize(new Map<String, Object>{\n            'sfId' => order.Id,\n            'name' => order.Name,\n            'total' => order.Total__c\n        }));\n\n        HttpResponse res = new Http().send(req);\n        if (res.getStatusCode() != 200) {\n            throw new CalloutException('Sync failed: '\n                + res.getBody());\n        }\n    }\n}" },
  { t: "README.md", c: "# Salesforce CRM Implementation\n\n## Objects\n| Object | Purpose |\n|--------|---------|\n| Account | Customer records |\n| Order__c | Custom orders |\n| Approval__c | Order approvals |\n\n## Automation\n- Flow: Order approval (>$10K)\n- Batch: Daily order processing\n- Platform Events: Audit logging\n\n## Integration\n- REST API: ERP sync\n- Platform Events: Real-time\n- Named Credentials: Secure callouts\n\n## Testing\n- Code coverage: >85%\n- Data factory: TestDataFactory.cls" },
]);
