export const servicenow: TechSnippetData = createEnterpriseTech("ServiceNow", "JavaScript", [
  { t: "acl_config.js", c: "// ServiceNow ACL Script\n(function executeRule(current, previous) {\n    // Check user role and assignment group\n    var hasRole = gs.hasRole('itil');\n    var isAssigned = current.assignment_group\n        .toString() === gs.getUser()\n        .getMyGroups().toString();\n\n    // Allow access only to assigned group members\n    answer = hasRole && isAssigned;\n\n    // Audit access attempt\n    if (!answer) {\n        gs.log('Access denied: ' + gs.getUserName()\n            + ' tried to access ' + current.number,\n            'SecurityAudit');\n    }\n})(current, previous);" },
  { t: "business_rule.js", c: "// ServiceNow Business Rule - Before Insert\n(function executeRule(current, previous) {\n    // Auto-assign based on category\n    var category = current.category.toString();\n    var assignmentMap = {\n        'network': 'Network Team',\n        'database': 'DBA Team',\n        'application': 'App Support'\n    };\n\n    if (assignmentMap[category]) {\n        var group = new GlideRecord('sys_user_group');\n        group.addQuery('name', assignmentMap[category]);\n        group.query();\n        if (group.next()) {\n            current.assignment_group = group.sys_id;\n        }\n    }\n\n    // Set priority from impact/urgency matrix\n    current.priority = calculatePriority(\n        current.impact, current.urgency);\n})(current, previous);" },
  { t: "atf_test.js", c: "// ServiceNow ATF Test\nvar runner = new sn_atf.AutomatedTestRunner();\n\n// Test: Incident creation\nvar test = runner.createTest('Incident Auto-Assignment');\ntest.addStep('create_record', {\n    table: 'incident',\n    values: {\n        short_description: 'Test incident',\n        category: 'network',\n        impact: '2',\n        urgency: '2'\n    }\n});\ntest.addStep('assert_field_value', {\n    field: 'assignment_group',\n    operator: 'is not empty'\n});\ntest.addStep('assert_field_value', {\n    field: 'priority',\n    value: '3'\n});\n\nrunner.run(test);" },
  { t: "audit_script.js", c: "// ServiceNow Audit Trail Script Include\nvar AuditLogger = Class.create();\nAuditLogger.prototype = {\n    initialize: function() {},\n\n    logChange: function(table, sysId, field, oldVal, newVal) {\n        var audit = new GlideRecord('u_custom_audit');\n        audit.initialize();\n        audit.u_table = table;\n        audit.u_record_id = sysId;\n        audit.u_field = field;\n        audit.u_old_value = oldVal;\n        audit.u_new_value = newVal;\n        audit.u_user = gs.getUserID();\n        audit.u_timestamp = new GlideDateTime();\n        audit.insert();\n    },\n\n    type: 'AuditLogger'\n};" },
  { t: "error_handler.js", c: "// ServiceNow Error Handler\nvar ErrorHandler = Class.create();\nErrorHandler.prototype = {\n    initialize: function() {\n        this.logger = new GSLog('com.webq', 'ErrorHandler');\n    },\n\n    handleError: function(error, context) {\n        this.logger.logErr('Error in ' + context\n            + ': ' + error.message);\n\n        // Create incident for critical errors\n        if (this.isCritical(error)) {\n            var inc = new GlideRecord('incident');\n            inc.initialize();\n            inc.short_description = 'Auto: ' + error.message;\n            inc.category = 'application';\n            inc.impact = '1';\n            inc.urgency = '1';\n            inc.assignment_group.setDisplayValue('App Support');\n            inc.insert();\n        }\n    },\n\n    type: 'ErrorHandler'\n};" },
  { t: "service_portal.js", c: "// ServiceNow Service Portal Widget\nfunction($scope, spUtil) {\n    var c = this;\n\n    c.data.loading = true;\n\n    // Fetch user's open incidents\n    c.server.get({\n        action: 'getMyIncidents'\n    }).then(function(response) {\n        c.data.incidents = response.data.incidents;\n        c.data.loading = false;\n    });\n\n    c.submitRequest = function() {\n        spUtil.confirm('Submit this request?')\n        .then(function() {\n            c.server.get({\n                action: 'createRequest',\n                description: c.data.description,\n                category: c.data.category\n            }).then(function(response) {\n                spUtil.addInfoMessage('Request ' +\n                    response.data.number + ' created');\n            });\n        });\n    };\n}" },
  { t: "flow_designer.json", c: "{\n  \"name\": \"Incident Escalation\",\n  \"trigger\": {\n    \"type\": \"record_update\",\n    \"table\": \"incident\",\n    \"condition\": \"priority=1 AND state=1\"\n  },\n  \"actions\": [\n    {\n      \"type\": \"timer\",\n      \"duration\": \"15 minutes\"\n    },\n    {\n      \"type\": \"condition\",\n      \"check\": \"state still = 1\",\n      \"then\": [\n        {\n          \"type\": \"update_record\",\n          \"fields\": {\n            \"escalation\": \"2\",\n            \"assignment_group\": \"Management\"\n          }\n        },\n        {\n          \"type\": \"notification\",\n          \"to\": \"on_call_manager\",\n          \"template\": \"P1 Escalation\"\n        }\n      ]\n    }\n  ]\n}" },
  { t: "integration_hub.js", c: "// ServiceNow IntegrationHub Spoke\nvar IntegrationSpoke = Class.create();\nIntegrationSpoke.prototype = {\n    initialize: function() {},\n\n    syncToExternalSystem: function(incidentSysId) {\n        var inc = new GlideRecord('incident');\n        inc.get(incidentSysId);\n\n        var rest = new sn_ws.RESTMessageV2(\n            'External ERP', 'POST');\n        rest.setRequestBody(JSON.stringify({\n            ticketId: inc.number.toString(),\n            description: inc.short_description.toString(),\n            priority: inc.priority.toString()\n        }));\n\n        var response = rest.execute();\n        if (response.getStatusCode() != 200) {\n            gs.error('Integration failed: '\n                + response.getBody());\n        }\n    },\n\n    type: 'IntegrationSpoke'\n};" },
  { t: "README.md", c: "# ServiceNow ITSM Implementation\n\n## Modules\n| Module | Purpose |\n|--------|---------|\n| ITSM | Incident, Problem, Change |\n| ITOM | Discovery, Event Mgmt |\n| CSM | Customer Service |\n| HRSD | HR Service Delivery |\n\n## Customizations\n- Auto-assignment business rules\n- SLA escalation flows\n- Service Portal widgets\n- IntegrationHub spokes\n\n## Testing\n- ATF: Automated Test Framework\n- Instance scan before upgrade\n\n## Support\n- L1: Service Portal\n- L2: Assignment groups\n- L3: Platform admin" },
]);
