export const dynamics365: TechSnippetData = createEnterpriseTech("Dynamics 365", "C#", [
  { t: "security_plugin.cs", c: "// Dynamics 365 Plugin with Security\npublic class OrderSecurity : IPlugin {\n    public void Execute(IServiceProvider serviceProvider) {\n        var context = (IPluginExecutionContext)\n            serviceProvider.GetService(typeof(IPluginExecutionContext));\n        var service = ((IOrganizationServiceFactory)\n            serviceProvider.GetService(typeof(IOrganizationServiceFactory)))\n            .CreateOrganizationService(context.UserId);\n\n        // Validate user has order approval role\n        var query = new QueryExpression(\"systemuserroles\");\n        query.Criteria.AddCondition(\"systemuserid\",\n            ConditionOperator.Equal, context.UserId);\n\n        var roles = service.RetrieveMultiple(query);\n        if (roles.Entities.Count == 0)\n            throw new InvalidPluginExecutionException(\n                \"Insufficient permissions\");\n    }\n}" },
  { t: "batch_operation.cs", c: "// Dynamics 365 Batch Operations\nvar batchId = $\"batch_{Guid.NewGuid()}\";\nvar changesetId = $\"changeset_{Guid.NewGuid()}\";\n\nvar requests = new OrganizationRequestCollection();\nforeach (var order in ordersToUpdate) {\n    requests.Add(new UpdateRequest {\n        Target = new Entity(\"salesorder\") {\n            Id = order.Id,\n            [\"statecode\"] = new OptionSetValue(1),\n            [\"statuscode\"] = new OptionSetValue(100001)\n        }\n    });\n}\n\nvar batchRequest = new ExecuteMultipleRequest {\n    Requests = requests,\n    Settings = new ExecuteMultipleSettings {\n        ContinueOnError = true,\n        ReturnResponses = true\n    }\n};\nvar response = (ExecuteMultipleResponse)\n    service.Execute(batchRequest);" },
  { t: "plugin_test.cs", c: "// Dynamics 365 Plugin Unit Test\n[TestClass]\npublic class OrderSecurityTests {\n    [TestMethod]\n    public void Execute_ValidUser_Succeeds() {\n        var context = new FakePluginExecutionContext {\n            UserId = Guid.NewGuid(),\n            MessageName = \"Create\"\n        };\n        var service = new FakeOrganizationService();\n        service.SetupRetrieveMultiple(\n            new EntityCollection(new List<Entity> {\n                new Entity(\"systemuserroles\")\n            }));\n\n        var plugin = new OrderSecurity();\n        plugin.Execute(new FakeServiceProvider(\n            context, service));\n        // Should not throw\n    }\n\n    [TestMethod]\n    [ExpectedException(typeof(InvalidPluginExecutionException))]\n    public void Execute_NoRole_ThrowsException() {\n        // Test with empty roles\n    }\n}" },
  { t: "audit_config.json", c: "{\n  \"auditSettings\": {\n    \"isAuditEnabled\": true,\n    \"isUserAccessAuditEnabled\": true,\n    \"auditRetentionPeriod\": 365\n  },\n  \"entityAudit\": [\n    {\n      \"entity\": \"salesorder\",\n      \"isAuditEnabled\": true,\n      \"attributes\": [\n        \"statecode\", \"statuscode\",\n        \"totalamount\", \"customerid\"\n      ]\n    },\n    {\n      \"entity\": \"contact\",\n      \"isAuditEnabled\": true,\n      \"attributes\": [\n        \"emailaddress1\", \"telephone1\",\n        \"address1_composite\"\n      ]\n    }\n  ]\n}" },
  { t: "error_handler.cs", c: "// Dynamics 365 Error Handling Plugin\npublic class OrderErrorHandler : IPlugin {\n    public void Execute(IServiceProvider serviceProvider) {\n        var trace = (ITracingService)\n            serviceProvider.GetService(typeof(ITracingService));\n        try {\n            ProcessOrder(serviceProvider);\n        } catch (FaultException<OrganizationServiceFault> ex) {\n            trace.Trace($\"Org error: {ex.Detail.Message}\");\n            if (ex.Detail.ErrorCode == -2147220891)\n                throw new InvalidPluginExecutionException(\n                    \"Record is locked by another user\");\n            throw new InvalidPluginExecutionException(\n                $\"Processing failed: {ex.Message}\");\n        } catch (Exception ex) {\n            trace.Trace($\"Unexpected: {ex}\");\n            throw new InvalidPluginExecutionException(\n                \"An unexpected error occurred\");\n        }\n    }\n}" },
  { t: "model_driven_app.json", c: "{\n  \"appName\": \"Order Management\",\n  \"navigation\": {\n    \"groups\": [\n      {\n        \"title\": \"Sales\",\n        \"pages\": [\n          {\"type\": \"entity\", \"entity\": \"salesorder\",\n           \"view\": \"Active Orders\"},\n          {\"type\": \"entity\", \"entity\": \"quote\",\n           \"view\": \"Open Quotes\"},\n          {\"type\": \"dashboard\",\n           \"name\": \"Sales Performance\"}\n        ]\n      }\n    ]\n  },\n  \"forms\": {\n    \"salesorder\": {\n      \"tabs\": [\"General\", \"Products\", \"Fulfillment\"],\n      \"businessRules\": [\n        \"Auto-calculate discount\",\n        \"Validate shipping address\"\n      ]\n    }\n  }\n}" },
  { t: "power_automate.json", c: "{\n  \"name\": \"Order Approval Flow\",\n  \"trigger\": {\n    \"type\": \"Dataverse\",\n    \"action\": \"When a row is added or modified\",\n    \"table\": \"salesorder\",\n    \"filter\": \"totalamount gt 50000\"\n  },\n  \"actions\": [\n    {\n      \"type\": \"Approval\",\n      \"approver\": \"@{triggerOutputs()?['body/ownerid']}\",\n      \"title\": \"Approve Order @{triggerOutputs()?['body/name']}\",\n      \"details\": \"Amount: @{triggerOutputs()?['body/totalamount']}\"\n    },\n    {\n      \"type\": \"Condition\",\n      \"if\": \"outcome eq 'Approve'\",\n      \"then\": {\"updateStatus\": \"Approved\"},\n      \"else\": {\"updateStatus\": \"Rejected\"}\n    }\n  ]\n}" },
  { t: "dataverse_api.cs", c: "// Dynamics 365 Web API Integration\nvar client = new HttpClient();\nclient.DefaultRequestHeaders.Authorization =\n    new AuthenticationHeaderValue(\"Bearer\", token);\nclient.BaseAddress = new Uri(\n    \"https://webq.crm.dynamics.com/api/data/v9.2/\");\n\n// Create order\nvar order = new {\n    name = \"ORD-2024-001\",\n    totalamount = 15000.00m,\n    customerid_account = new {\n        accountid = customerId\n    }\n};\n\nvar response = await client.PostAsJsonAsync(\n    \"salesorders\", order);\n\nif (response.IsSuccessStatusCode) {\n    var location = response.Headers.Location;\n    Console.WriteLine($\"Created: {location}\");\n}" },
  { t: "README.md", c: "# Dynamics 365 Implementation\n\n## Modules\n| Module | Purpose |\n|--------|---------|\n| Sales | Pipeline, quotes, orders |\n| Service | Case management |\n| Finance | GL, AP, AR |\n| Supply Chain | Inventory, procurement |\n\n## Customizations\n- Plugins: Server-side logic\n- Power Automate: Workflow automation\n- Model-driven apps: Custom UI\n- Dataverse: Data platform\n\n## Integration\n- Web API (REST/OData)\n- Power Automate connectors\n- Azure Service Bus\n\n## DevOps\n- Solution management\n- ALM with Azure DevOps" },
]);
